# ── Session state initialisation ──────────────────────────────────────────────
def init_state():
    import hashlib as _hl
    _admin = {"id":ADMIN_ID,"email":ADMIN_EMAIL,"username":ADMIN_USERNAME,"pw_hash":"","rec":"","is_admin":True}

    defaults = {
        "screen":      "apikey",
        "groq_key":    "",
        "users":       [_admin],   # admin pre-seeded
        "session":     None,       # logged-in user dict
        "profile":     None,       # onboarding profile dict
        "spaces":      [],         # list of space dicts
        "notes":       {},         # {space_id: [note dicts]}
        "cur_space":   None,       # currently open space
        "ob_step":     0,          # onboarding step
        "ob_grade":    "",
        "ob_region":   "",
        "ob_curr":     "",
        "ob_picked":   [],         # picked subjects
        "ob_profs":    {},         # proficiency per subject id
        "tip_idx":     random.randint(0, len(STUDY_TIPS)-1),
        "open_note":   None,       # note being viewed
        "plan_text":   "",         # generated study plan
        "plan_loading":False,
    }
    for k, v in defaults.items():
        if k not in st.session_state:
            st.session_state[k] = v

# ── Groq helpers ──────────────────────────────────────────────────────────────
def get_groq():
    """Return a Groq client using the stored key."""
    return Groq(api_key=st.session_state.groq_key)

def subStr(profile):
    return ", ".join(
        f"{s['name']} ({s['proficiency']})"
        for s in (profile.get("subjects") or [])
    ) or "General"

def ai_analyze_image(image_bytes: bytes, profile: dict) -> str:
    """Send an image to Groq vision model and return study notes."""
    client = get_groq()
    b64 = base64.b64encode(image_bytes).decode()
    subs = subStr(profile)
    resp = client.chat.completions.create(
        model="meta-llama/llama-4-scout-17b-16e-instruct",
        messages=[{
            "role": "user",
            "content": [
                {"type": "image_url",
                 "image_url": {"url": f"data:image/jpeg;base64,{b64}"}},
                {"type": "text",
                 "text": (
                    f"You are Elixir AI, expert tutor for {profile['grade']} "
                    f"{profile['curriculum']} students in {profile['region']}. "
                    f"Subjects: {subs}.\n\n"
                    "Analyse ONLY what is visible in this image. Do NOT generate routines.\n\n"
                    "**Key Concepts** - Main topics visible in this image\n"
                    "**Study Notes** - Notes from this image only\n"
                    "**Step-by-Step Breakdowns** - Simplify complex parts shown\n"
                    "**Study Tips** - 3 tips specific to this content\n"
                    "**Check Your Understanding** - 3 questions from this image"
                 )}
            ]
        }],
        max_tokens=1024,
    )
    return resp.choices[0].message.content or ""

def ai_analyze_text(text: str, profile: dict) -> str:
    """Send text content to Groq and return study notes."""
    client = get_groq()
    subs = subStr(profile)
    clean = "".join(c for c in text if ord(c) >= 32 or c in "\n\t")
    trunc = clean[:6000] + ("\n\n[truncated]" if len(clean) > 6000 else "")
    resp = client.chat.completions.create(
        model="llama-3.3-70b-versatile",
        messages=[
            {"role": "system",
             "content": (
                f"You are Elixir AI, expert tutor for {profile['grade']} "
                f"{profile['curriculum']} in {profile['region']}. "
                f"Subjects: {subs}. Be clear and encouraging."
             )},
            {"role": "user",
             "content": (
                "Analyse ONLY the uploaded file content. Do NOT generate routines.\n\n"
                "**Key Concepts** - Main topics in this file\n"
                "**Study Notes** - Notes from the uploaded content only\n"
                "**Step-by-Step Breakdowns** - Simplify complex parts in the file\n"
                "**Study Tips** - 3 tips specific to this content\n"
                "**Check Your Understanding** - 3 questions from this file\n\n"
                f"---\n\n{trunc}"
             )}
        ],
        max_tokens=1024,
    )
    return resp.choices[0].message.content or ""

def ai_study_plan(profile: dict) -> str:
    """Generate a personalised weekly study plan."""
    client = get_groq()
    subs = subStr(profile)
    resp = client.chat.completions.create(
        model="llama-3.3-70b-versatile",
        messages=[{"role": "user", "content": (
            f"Weekly study plan for {profile['grade']} {profile['curriculum']} "
            f"student in {profile['region']}. Subjects: {subs}.\n"
            "Include Mon&#8211;Sun with daily subject slots, specific techniques, "
            "Pomodoro breaks, weekend review. Use bold day headers."
        )}],
        max_tokens=1024,
    )
    return resp.choices[0].message.content or ""

