def screen_signup():
    """Sign up screen."""
    col = st.columns([1,2,1])[1]
    with col:
        if st.button("← Back"): go("welcome")
        st.markdown('<h2 style="font-weight:900;margin-bottom:4px">Create your account</h2>', unsafe_allow_html=True)
        st.markdown('<p style="color:#6E6E6B;font-size:13px;margin-bottom:20px">Join Elixir and start studying smarter.</p>', unsafe_allow_html=True)

        email    = st.text_input("Email address", placeholder="you@email.com")
        username = st.text_input("Username", placeholder="studystar99")
        pw       = st.text_input("Password", type="password", placeholder="Create a strong password")
        cpw      = st.text_input("Confirm password", type="password", placeholder="Repeat your password")
        rec      = st.text_input("Recovery email (optional)", placeholder="backup@email.com")

        # Password strength indicator
        if pw:
            n = sum([len(pw)>=8, len(pw)>=12,
                     any(c.isupper() for c in pw) and any(c.islower() for c in pw),
                     any(c.isdigit() for c in pw),
                     any(not c.isalnum() for c in pw)])
            labels = ["Too short","Weak","Fair","Good","Strong","Very strong"]
            colors = ["#dc2626","#ef4444","#d97706","#16a34a","#16a34a","#0ea5e9"]
            pct    = int((n/5)*100)
            lbl    = labels[min(n,5)]
            col_  = colors[min(n,5)]
            st.markdown(
                f'<div style="display:flex;align-items:center;gap:10px;margin-bottom:4px">' +
                f'<div style="flex:1;height:4px;background:#E6E6E3;border-radius:4px;overflow:hidden">' +
                f'<div style="width:{pct}%;height:100%;background:{col_};transition:width .3s"></div></div>' +
                f'<span style="font-size:12px;font-weight:800;color:{col_};min-width:80px">{lbl}</span></div>',
                unsafe_allow_html=True
            )

        if st.button("Create account →", use_container_width=True):
            err = None
            if "@" not in email: err = "Enter a valid email."
            elif len(username)<3 or not username.replace("_","").isalnum(): err = "Username: 3+ chars, letters/numbers/underscores."
            elif any(u["email"]==email for u in st.session_state.users): err = "Email already registered."
            elif any(u["username"].lower()==username.lower() for u in st.session_state.users): err = "Username taken."
            elif n < 2: err = "Password is too weak."
            elif pw != cpw: err = "Passwords do not match."
            if err:
                st.error(err)
            else:
                import hashlib
                user = {"id":f"u{int(time.time()*1000)}","email":email,
                        "username":username,"pw_hash":hashlib.sha256(pw.encode()).hexdigest(),
                        "rec":rec}
                st.session_state.users.append(user)
                st.session_state.session = {"id":user["id"],"email":email,"username":username}
                go("onboard")

        st.markdown('<p style="text-align:center;margin-top:14px;font-size:13px;color:#6E6E6B">Already have an account? </p>', unsafe_allow_html=True)
        if st.button("Sign in instead", use_container_width=False): go("signin")


def screen_signin():
    """Sign in screen."""
    col = st.columns([1,2,1])[1]
    with col:
        if st.button("← Back"): go("welcome")
        st.markdown('<h2 style="font-weight:900;margin-bottom:4px">Welcome back</h2>', unsafe_allow_html=True)
        st.markdown('<p style="color:#6E6E6B;font-size:13px;margin-bottom:20px">Sign in to your Elixir account.</p>', unsafe_allow_html=True)

        email = st.text_input("Email", placeholder="you@email.com")
        pw    = st.text_input("Password", type="password", placeholder="Your password")

        if st.button("Sign in →", use_container_width=True):
            import hashlib
            # Admin: email match only, no password needed
            if email.strip().lower() == ADMIN_EMAIL.lower():
                st.session_state.session = {"id":ADMIN_ID,"email":ADMIN_EMAIL,"username":ADMIN_USERNAME,"is_admin":True}
                go("dashboard" if st.session_state.profile else "onboard")
            else:
                pw_hash = hashlib.sha256(pw.encode()).hexdigest()
                user = next((u for u in st.session_state.users
                             if u["email"]==email and u["pw_hash"]==pw_hash), None)
                if not user:
                    st.error("Incorrect email or password.")
                else:
                    st.session_state.session = {"id":user["id"],"email":email,"username":user["username"],"is_admin":False}
                    go("dashboard" if st.session_state.profile else "onboard")

        st.markdown('<p style="text-align:center;margin-top:14px;font-size:13px;color:#6E6E6B">No account? </p>', unsafe_allow_html=True)
        if st.button("Create one", use_container_width=False): go("signup")


def screen_onboard():
    """3-step onboarding."""
    step = st.session_state.ob_step
    col  = st.columns([1,2,1])[1]
    with col:
        # Progress bar
        st.markdown(
            f'<p style="font-size:11px;font-weight:700;color:#6E6E6B;margin-bottom:4px">STEP {step+1} OF 3</p>',
            unsafe_allow_html=True
        )
        st.progress((step+1)/3)
        st.markdown("<br/>", unsafe_allow_html=True)

        if step == 0:
            st.markdown('<h3 style="font-weight:900">Personalise your experience</h3>', unsafe_allow_html=True)
            st.markdown('<p style="color:#6E6E6B;font-size:13px;margin-bottom:18px">Tell us about your studies so Elixir can tailor everything.</p>', unsafe_allow_html=True)
            st.session_state.ob_grade  = st.selectbox("Year / Grade",  [""] + GRADES,   index=GRADES.index(st.session_state.ob_grade)+1  if st.session_state.ob_grade  else 0)
            st.session_state.ob_region = st.selectbox("Study Region",  [""] + REGIONS,  index=REGIONS.index(st.session_state.ob_region)+1 if st.session_state.ob_region else 0)
            st.session_state.ob_curr   = st.selectbox("Curriculum",    [""] + CURRICULA,index=CURRICULA.index(st.session_state.ob_curr)+1 if st.session_state.ob_curr   else 0)
            ok = bool(st.session_state.ob_grade and st.session_state.ob_region and st.session_state.ob_curr)
            if st.button("Next: Pick subjects →", use_container_width=True, disabled=not ok):
                st.session_state.ob_step = 1
                st.rerun()

        elif step == 1:
            st.markdown('<h3 style="font-weight:900">Which subjects do you study?</h3>', unsafe_allow_html=True)
            st.markdown('<p style="color:#6E6E6B;font-size:13px;margin-bottom:16px">Select all that apply.</p>', unsafe_allow_html=True)
            picked = list(st.session_state.ob_picked)
            cols = st.columns(2)
            for i, (sid, name, icon) in enumerate(SUBJECTS):
                is_sel = sid in picked
                with cols[i % 2]:
                    chk = "\u2713 " if is_sel else ""
                    label = f"{chk}{icon}  {name}"
                    cls = "sub-sel" if is_sel else "sub-unsel"
                    st.markdown(f'<div class="{cls}">', unsafe_allow_html=True)
                    if st.button(label, key=f"sub_{sid}", use_container_width=True):
                        if is_sel: picked.remove(sid)
                        else:      picked.append(sid)
                        st.session_state.ob_picked = picked
                        st.rerun()
                    st.markdown('</div>', unsafe_allow_html=True)
            st.markdown("<br/>", unsafe_allow_html=True)
            c1, c2 = st.columns(2)
            with c1:
                if st.button("← Back", use_container_width=True): st.session_state.ob_step=0; st.rerun()
            with c2:
                if st.button("Next →", use_container_width=True, disabled=not picked):
                    st.session_state.ob_step = 2; st.rerun()

        elif step == 2:
            st.markdown('<h3 style="font-weight:900">How confident are you?</h3>', unsafe_allow_html=True)
            st.markdown('<p style="color:#6E6E6B;font-size:13px;margin-bottom:16px">Be honest &#8212; this shapes your study plan.</p>', unsafe_allow_html=True)
            profs = dict(st.session_state.ob_profs)
            picked_subs = [(sid,name,icon) for sid,name,icon in SUBJECTS if sid in st.session_state.ob_picked]
            for sid, name, icon in picked_subs:
                current = profs.get(sid, "Developing")
                idx     = PROFICIENCY.index(current)
                choice  = st.select_slider(f"{icon} {name}", options=PROFICIENCY, value=current, key=f"prof_{sid}")
                profs[sid] = choice
            st.session_state.ob_profs = profs
            st.markdown("<br/>", unsafe_allow_html=True)
            c1, c2 = st.columns(2)
            with c1:
                if st.button("← Back", use_container_width=True): st.session_state.ob_step=1; st.rerun()
            with c2:
                if st.button("Start studying →", use_container_width=True):
                    subjects = [
                        {"id":sid,"name":name,"icon":icon,
                         "proficiency": st.session_state.ob_profs.get(sid,"Developing")}
                        for sid,name,icon in SUBJECTS
                        if sid in st.session_state.ob_picked
                    ]
                    st.session_state.profile = {
                        "grade":      st.session_state.ob_grade,
                        "region":     st.session_state.ob_region,
                        "curriculum": st.session_state.ob_curr,
                        "subjects":   subjects,
                    }
                    go("dashboard")


def screen_dashboard():
    """Main dashboard."""
    session = st.session_state.session
    profile = st.session_state.profile
    spaces  = st.session_state.spaces
    hr      = __import__("datetime").datetime.now().hour
    greet   = "morning" if hr<12 else ("afternoon" if hr<18 else "evening")

    # ── Header ──────────────────────────────────────────────────────────────
    h_col1, h_col2 = st.columns([1, 6])
    with h_col1:
        st.markdown(
            f'<img src="data:image/png;base64,{LOGO_B64}" width="40"/>',
            unsafe_allow_html=True
        )
    with h_col2:
        st.markdown(
            f'<div style="display:flex;align-items:center;justify-content:flex-end;gap:12px;padding-top:4px">' +
            f'<span style="font-size:13px;color:#6E6E6B;font-weight:700">Hi, {session["username"]}</span></div>',
            unsafe_allow_html=True
        )
    st.markdown('<hr class="elixir-divider"/>', unsafe_allow_html=True)

    # ── Greeting ─────────────────────────────────────────────────────────────
    is_admin = session.get("is_admin", False)
    badge = ' <span style="font-size:12px;font-weight:800;padding:2px 10px;border-radius:20px;background:#3BBFAF22;color:#3BBFAF">Admin</span>' if is_admin else ""
    st.markdown(f'<h2 style="font-weight:900;margin-bottom:4px">Good {greet}, {session["username"]}{badge}</h2>', unsafe_allow_html=True)
    st.markdown(f'<p style="color:#6E6E6B;font-size:14px;margin-bottom:24px">{profile["grade"]} · {profile["curriculum"]} · {profile["region"]}</p>', unsafe_allow_html=True)

    left, right = st.columns([3, 2], gap="large")

    # ── Left: Spaces ─────────────────────────────────────────────────────────
    with left:
        sc1, sc2 = st.columns([1,1])
        with sc1:
            st.markdown('<h3 style="font-weight:900;font-size:17px">Spaces</h3>', unsafe_allow_html=True)
        with sc2:
            if st.button("+ New space", key="new_space_btn"): go("new_space")

        if not spaces:
            st.markdown(
                '<div style="border:2px dashed #E6E6E3;border-radius:13px;padding:30px;text-align:center">' +
                '<p style="color:#6E6E6B;font-size:14px">No spaces yet. Create your first study space!</p></div>',
                unsafe_allow_html=True
            )
        else:
            scols = st.columns(2)
            for i, sp in enumerate(spaces):
                with scols[i % 2]:
                    st.markdown(
                        f'<div class="space-card" style="border-left:4px solid {sp["color"]}">' +
                        f'<div style="display:flex;align-items:center;gap:9px;margin-bottom:7px">' +
                        f'<div style="width:33px;height:33px;border-radius:8px;background:{sp["color"]}26;' +
                        f'display:flex;align-items:center;justify-content:center;font-size:17px;color:{sp["color"]}">{sp["icon"]}</div>' +
                        f'<div><div style="font-weight:800;font-size:13px">{sp["name"]}</div>' +
                        f'<div style="font-size:11px;color:#ADADAA">Study space</div></div></div>' +
                        f'<div style="font-size:11px;color:#6E6E6B">● {sp["subject"]}</div></div>',
                        unsafe_allow_html=True
                    )
                    if st.button(f"Open {sp['name']}", key=f"open_sp_{sp['id']}", use_container_width=True):
                        st.session_state.cur_space = sp
                        go("space")

        # Study plan card
        st.markdown("<br/>", unsafe_allow_html=True)
        st.markdown(
            '<div class="elixir-card" style="background:#EAF8F6;border:1px solid #3BBFAF44">' +
            '<div style="font-weight:800;font-size:15px;margin-bottom:4px">Weekly Study Plan</div>' +
            '<div style="font-size:12px;color:#6E6E6B">AI-generated, personalised to your subjects.</div></div>',
            unsafe_allow_html=True
        )
        if st.button("Generate study plan", use_container_width=True, key="gen_plan"):
            go("studyplan")

    # ── Right: Tips + Subjects ────────────────────────────────────────────────
    with right:
        # Study tips
        st.markdown('<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">' +
                    '<span style="font-weight:800;font-size:13px">Study Tips</span></div>', unsafe_allow_html=True)
        tip = STUDY_TIPS[st.session_state.tip_idx]
        st.markdown(f'<div class="tip-box">{tip}</div>', unsafe_allow_html=True)
        tc1, tc2 = st.columns(2)
        with tc1:
            if st.button("← Prev", use_container_width=True, key="tip_prev"):
                st.session_state.tip_idx = (st.session_state.tip_idx - 1) % len(STUDY_TIPS)
                st.rerun()
        with tc2:
            if st.button("Next →", use_container_width=True, key="tip_next"):
                st.session_state.tip_idx = (st.session_state.tip_idx + 1) % len(STUDY_TIPS)
                st.rerun()
        st.markdown(
            f'<p style="font-size:11px;color:#ADADAA;text-align:right">{st.session_state.tip_idx+1} of {len(STUDY_TIPS)}</p>',
            unsafe_allow_html=True
        )

        st.markdown("<br/>", unsafe_allow_html=True)

        # Subjects list
        st.markdown('<div style="font-weight:800;font-size:13px;margin-bottom:10px">Your subjects</div>', unsafe_allow_html=True)
        for s in (profile.get("subjects") or [])[:8]:
            col_ = PROF_COLORS.get(s["proficiency"], "#888")
            st.markdown(
                f'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px">' +
                f'<span style="font-size:12px">{s["icon"]} {s["name"]}</span>' +
                f'<span style="font-size:10px;font-weight:800;padding:2px 8px;border-radius:20px;' +
                f'background:{col_}22;color:{col_}">{s["proficiency"]}</span></div>',
                unsafe_allow_html=True
            )

        # Settings
        st.markdown("<br/>", unsafe_allow_html=True)
        with st.expander("⚙ Settings"):
            st.markdown(f"**{session['username']}** · {session['email']}")
            st.markdown(f"{profile['grade']} · {profile['curriculum']} · {profile['region']}")
            st.markdown("---")
            if st.button("Sign out", use_container_width=True):
                for k in ["session","profile","spaces","notes","cur_space",
                          "ob_step","ob_grade","ob_region","ob_curr","ob_picked","ob_profs"]:
                    st.session_state[k] = [] if k in ("spaces","ob_picked") else ({} if k in ("notes","ob_profs") else (None if k!="ob_step" else 0))
                go("welcome")


def screen_new_space():
    """Create a new space."""
    profile = st.session_state.profile
    col = st.columns([1,2,1])[1]
    with col:
        if st.button("← Dashboard"): go("dashboard")
        st.markdown('<h3 style="font-weight:900;margin-bottom:20px">Create a space</h3>', unsafe_allow_html=True)

        name  = st.text_input("Space name", placeholder="e.g. Biology Revision")
        icon  = st.selectbox("Icon", SPACE_ICONS)
        color_name = st.selectbox("Colour", list(SPACE_COLORS.keys()))
        color = SPACE_COLORS[color_name]

        subj_names = ["General"] + [s["name"] for s in (profile.get("subjects") or [])]
        subj = st.selectbox("Subject (optional)", subj_names)

        if st.button("Create space", use_container_width=True, disabled=not name.strip()):
            sp = {"id":f"sp{int(time.time()*1000)}","name":name.strip(),
                  "icon":icon,"color":color,"subject":subj}
            st.session_state.spaces.insert(0, sp)
            st.session_state.cur_space = sp
            go("space")


def screen_space():
    """Space view &#8212; upload and analyse files."""
    space   = st.session_state.cur_space
    profile = st.session_state.profile
    notes   = st.session_state.notes.get(space["id"], [])

    # Header
    h1, h2 = st.columns([1, 8])
    with h1:
        if st.button("←"): go("dashboard")
    with h2:
        st.markdown(
            f'<div style="display:flex;align-items:center;gap:9px;padding-top:4px">' +
            f'<div style="width:28px;height:28px;border-radius:7px;background:{space["color"]}26;' +
            f'display:flex;align-items:center;justify-content:center;font-size:15px;color:{space["color"]}">{space["icon"]}</div>' +
            f'<span style="font-weight:900;font-size:15px">{space["name"]}</span></div>',
            unsafe_allow_html=True
        )
    st.markdown('<hr class="elixir-divider"/>', unsafe_allow_html=True)

    # File uploader
    st.markdown('<p style="font-weight:800;font-size:14px;margin-bottom:8px">Upload notes or a file</p>', unsafe_allow_html=True)
    uploaded = st.file_uploader(
        "Upload a file",
        type=["png","jpg","jpeg","gif","webp","txt","md","csv","json","py","js","ts","java","cpp","c","xml","yaml","yml","tex","log"],
        label_visibility="collapsed",
        help="Images, .txt, .md, .py, .csv and more"
    )

    if uploaded:
        st.markdown(
            f'<div class="tip-box">📄 <strong>{uploaded.name}</strong> &#8212; ready to analyse</div>',
            unsafe_allow_html=True
        )
        if st.button("⚗ Analyse with Elixir AI", use_container_width=True):
            is_image = uploaded.type.startswith("image/")
            prog = st.progress(0, text="Reading file...")
            prog.progress(20, text="Preparing content...")
            with st.spinner(f"Elixir AI is analysing {uploaded.name}..."):
                try:
                    raw   = uploaded.read()
                    if is_image:
                        analysis = ai_analyze_image(raw, profile)
                    else:
                        analysis = ai_analyze_text(raw.decode("utf-8","ignore"), profile)

                    b64_thumb = base64.b64encode(raw).decode() if is_image else None
                    prog.progress(85, text="Saving note...")
                    prog.progress(85, text="Saving note...")
                    note = {
                        "id":        f"n{int(time.time()*1000)}",
                        "title":     uploaded.name.rsplit(".",1)[0],
                        "is_image":  is_image,
                        "b64_thumb": b64_thumb,
                        "analysis":  analysis,
                        "filename":  uploaded.name,
                        "created":   __import__("datetime").datetime.now().strftime("%d %b %Y"),
                    }
                    if space["id"] not in st.session_state.notes:
                        st.session_state.notes[space["id"]] = []
                    st.session_state.notes[space["id"]].insert(0, note)
                    prog.progress(100, text="Done!")
                    prog.progress(100, text="Done!")
                    st.success("Note saved!")
                    st.rerun()
                except Exception as e:
                    prog.empty()
                    st.error(f"Analysis failed: {e}")

    # Notes list
    if notes:
        st.markdown(f'<h4 style="font-weight:900;font-size:15px;margin-top:24px;margin-bottom:12px">Analysed notes ({len(notes)})</h4>', unsafe_allow_html=True)
        for note in notes:
            with st.expander(f"{'🖼' if note['is_image'] else '📄'}  {note['title']} &#8212; {note['created']}"):
                if note["is_image"] and note.get("b64_thumb"):
                    st.image(base64.b64decode(note["b64_thumb"]), use_container_width=True)
                st.markdown(note["analysis"])
                if st.button("Copy to clipboard", key=f"copy_{note['id']}"):
                    st.code(note["analysis"])
    else:
        st.markdown('<p style="text-align:center;color:#ADADAA;font-size:13px;margin-top:24px">No notes yet. Upload a file to begin!</p>', unsafe_allow_html=True)


def screen_studyplan():
    """AI-generated weekly study plan."""
    profile = st.session_state.profile
    col = st.columns([1,2,1])[1]
    with col:
        if st.button("← Dashboard"): go("dashboard")
        st.markdown('<h2 style="font-weight:900;margin-bottom:20px">Weekly Study Plan</h2>', unsafe_allow_html=True)

        if not st.session_state.plan_text:
            with st.spinner("⚗ Building your personalised study plan…"):
                try:
                    st.session_state.plan_text = ai_study_plan(profile)
                except Exception as e:
                    st.error(f"Could not generate plan: {e}")
                    return

        st.markdown(
            f'<div class="analysis-box">{st.session_state.plan_text.replace(chr(10),"<br/>")}</div>',
            unsafe_allow_html=True
        )
        c1, c2 = st.columns(2)
        with c1:
            if st.button("Regenerate", use_container_width=True):
                st.session_state.plan_text = ""
                st.rerun()
        with c2:
            st.download_button("Download plan", st.session_state.plan_text,
                               file_name="study_plan.txt", mime="text/plain",
                               use_container_width=True)

# ── Router ────────────────────────────────────────────────────────────────────
def main():
    init_state()
    inject_css()

    screen = st.session_state.screen
    if   screen == "apikey":    screen_apikey()
    elif screen == "welcome":   screen_welcome()
    elif screen == "signup":    screen_signup()
    elif screen == "signin":    screen_signin()
    elif screen == "onboard":   screen_onboard()
    elif screen == "dashboard": screen_dashboard()
    elif screen == "new_space": screen_new_space()
    elif screen == "space":     screen_space()
    elif screen == "studyplan": screen_studyplan()
    else:
        st.error(f"Unknown screen: {screen}")
        go("welcome")

if __name__ == "__main__":
    main()
